'use client'

import { useState } from 'react'

export default function SIPCalculator() {
  const [monthly, setMonthly] = useState('')
  const [rate, setRate] = useState('')
  const [years, setYears] = useState('')
  const [result, setResult] = useState<number | null>(null)

  function calculate() {
    const P = parseFloat(monthly || '0')
    const r = parseFloat(rate || '0') / 100 / 12
    const n = parseFloat(years || '0') * 12
    if (!P || !r || !n) return setResult(0)
    const maturity = P * (Math.pow(1 + r, n) - 1) / r * (1 + r)
    setResult(maturity)
  }

  function reset() {
    setMonthly('')
    setRate('')
    setYears('')
    setResult(null)
  }

  return (
    <main className="container mx-auto p-4">
      <h1 className="text-2xl font-bold">SIP Calculator</h1>
      <p className="text-slate-600 dark:text-slate-300">Calculate expected maturity for monthly SIPs.</p>

      <div className="mt-6 max-w-md">
        <label className="block">
          <span>Monthly Investment (₹)</span>
          <input value={monthly} onChange={e => setMonthly(e.target.value)} className="w-full p-2 border rounded mt-1" />
        </label>

        <label className="block mt-3">
          <span>Expected Annual Return (%)</span>
          <input value={rate} onChange={e => setRate(e.target.value)} className="w-full p-2 border rounded mt-1" />
        </label>

        <label className="block mt-3">
          <span>Tenure (years)</span>
          <input value={years} onChange={e => setYears(e.target.value)} className="w-full p-2 border rounded mt-1" />
        </label>

        <div className="flex gap-2 mt-4">
          <button onClick={calculate} className="px-4 py-2 bg-blue-600 text-white rounded">Calculate</button>
          <button onClick={reset} className="px-4 py-2 border rounded">Reset</button>
        </div>

        {result !== null && (
          <div className="mt-4 p-4 bg-slate-50 dark:bg-slate-800 rounded">
            <div className="font-semibold">Maturity Amount</div>
            <div className="text-2xl">₹ {result.toFixed(2)}</div>
            <div className="mt-2 flex gap-2">
              <button className="px-3 py-1 bg-slate-200 rounded">Copy</button>
              <button className="px-3 py-1 border rounded">Share</button>
            </div>
          </div>
        )}
      </div>
    </main>
  )
}
